public class EventProcessor : IDisposable
{
    private readonly ManualResetEventSlim _newEvent = new();
    private readonly Queue<string> _queue = new();
    private readonly object _lock = new();
    private Thread? _thread;
    private CancellationTokenSource? _cts;

    public void Start()
    {
        _cts = new CancellationTokenSource();
        _thread = new Thread(() => RunLoop(_cts.Token));
        _thread.Start();
    }

    private void RunLoop(CancellationToken token)
    {
        try
        {
            while (!token.IsCancellationRequested)
            {
                // Wait on BOTH the event AND the cancellation token.
                // This replaces Thread.Interrupt() for waking blocked threads.
                WaitHandle.WaitAny([_newEvent.WaitHandle, token.WaitHandle]);

                if (token.IsCancellationRequested)
                    break;

                _newEvent.Reset();

                // Drain all queued items (fixes a latent bug in the original
                // where rapid Enqueue calls could leave items stranded).
                while (true)
                {
                    string? item;
                    lock (_lock)
                    {
                        if (_queue.Count == 0) break;
                        item = _queue.Dequeue();
                    }
                    Handle(item);
                }
            }
        }
        catch (OperationCanceledException)
        {
            // Expected on shutdown — nothing to do.
        }
    }

    public void Enqueue(string item)
    {
        lock (_lock) { _queue.Enqueue(item); }
        _newEvent.Set();
    }

    public void Stop()
    {
        _cts?.Cancel();           // signals the token → wakes WaitAny
        _thread?.Join(5000);      // wait up to 5 s for graceful exit
        // No Thread.Abort fallback needed — the loop checks the token
        // cooperatively and will exit.
    }

    public void Dispose()
    {
        Stop();
        _cts?.Dispose();
        _newEvent.Dispose();
    }
}
